class Solution:
    def countLocalMaximums(self, matrix):
        n = len(matrix)
        m = len(matrix[0]) if n else 0
        count = 0
        for row in range(n):
            for col in range(m):
                x = matrix[row][col]
                if x == 0:
                    continue
                ok = True
                for dr in range(-x, x + 1):
                    for dc in range(-x, x + 1):
                        if abs(dr) == x and abs(dc) == x:
                            continue
                        r, c = row + dr, col + dc
                        if 0 <= r < n and 0 <= c < m:
                            if matrix[r][c] > x:
                                ok = False
                                break
                    if not ok:
                        break
                if ok:
                    count += 1
        return count

