var countLocalMaximums = function(matrix) {
    const n = matrix.length;
    const m = n ? matrix[0].length : 0;
    if (n === 0 || m === 0) return 0;

    function bitLength(x) {
        let b = 0;
        while (x > 0) { x >>= 1; b++; }
        return b;
    }

    const LOGN = Math.max(1, bitLength(n));
    const LOGM = Math.max(1, bitLength(m));

    const sparse = [];
    for (let k1 = 0; k1 < LOGN; k1++) sparse.push(new Array(LOGM).fill(null));
    sparse[0][0] = matrix.map(row => row.slice());

    for (let k1 = 1; k1 < LOGN; k1++) {
        const h = 1 << k1;
        if (h > n) break;
        const half = 1 << (k1 - 1);
        const prev = sparse[k1 - 1][0];
        const cur = [];
        for (let i = 0; i <= n - h; i++) {
            const rowA = prev[i];
            const rowB = prev[i + half];
            const curRow = new Array(m);
            for (let j = 0; j < m; j++) {
                curRow[j] = rowA[j] > rowB[j] ? rowA[j] : rowB[j];
            }
            cur.push(curRow);
        }
        sparse[k1][0] = cur;
    }

    for (let k1 = 0; k1 < LOGN; k1++) {
        if (sparse[k1][0] === null) continue;
        const rowsAvail = n - (1 << k1) + 1;
        for (let k2 = 1; k2 < LOGM; k2++) {
            const w = 1 << k2;
            if (w > m) break;
            const half = 1 << (k2 - 1);
            const prev = sparse[k1][k2 - 1];
            const cur = [];
            for (let i = 0; i < rowsAvail; i++) {
                const prow = prev[i];
                const crow = new Array(m - w + 1);
                for (let j = 0; j <= m - w; j++) {
                    const a = prow[j];
                    const b = prow[j + half];
                    crow[j] = a > b ? a : b;
                }
                cur.push(crow);
            }
            sparse[k1][k2] = cur;
        }
    }

    function query(r0, r1, c0, c1) {
        if (r0 > r1 || c0 > c1) return null;
        const h = r1 - r0 + 1;
        const w = c1 - c0 + 1;
        const k1 = bitLength(h) - 1;
        const k2 = bitLength(w) - 1;
        const table = sparse[k1][k2];
        const rOff2 = r1 - (1 << k1) + 1;
        const cOff2 = c1 - (1 << k2) + 1;
        const a = table[r0][c0];
        const b = table[r0][cOff2];
        const c = table[rOff2][c0];
        const d = table[rOff2][cOff2];
        let best = a;
        if (b > best) best = b;
        if (c > best) best = c;
        if (d > best) best = d;
        return best;
    }

    let count = 0;
    for (let row = 0; row < n; row++) {
        for (let col = 0; col < m; col++) {
            const x = matrix[row][col];
            if (x === 0) continue;
            const r0 = Math.max(0, row - x);
            const r1 = Math.min(n - 1, row + x);
            const c0 = Math.max(0, col - x);
            const c1 = Math.min(m - 1, col + x);

            const hasTl = (row - x >= 0) && (col - x >= 0);
            const hasTr = (row - x >= 0) && (col + x <= m - 1);
            const hasBl = (row + x <= n - 1) && (col - x >= 0);
            const hasBr = (row + x <= n - 1) && (col + x <= m - 1);

            let reduced;
            if (r0 === r1) {
                reduced = query(r0, r1, c0, c1);
            } else {
                const topStart = hasTl ? c0 + 1 : c0;
                const topEnd = hasTr ? c1 - 1 : c1;
                const topMax = topStart <= topEnd ? query(r0, r0, topStart, topEnd) : null;

                const botStart = hasBl ? c0 + 1 : c0;
                const botEnd = hasBr ? c1 - 1 : c1;
                const botMax = botStart <= botEnd ? query(r1, r1, botStart, botEnd) : null;

                const midMax = (r0 + 1 <= r1 - 1) ? query(r0 + 1, r1 - 1, c0, c1) : null;

                reduced = null;
                for (const v of [topMax, botMax, midMax]) {
                    if (v !== null && (reduced === null || v > reduced)) reduced = v;
                }
            }

            if (reduced === null || reduced <= x) count++;
        }
    }
    return count;
};
